// Arbeitnow: paginate up to 5 pages, filter client-side, tag English heuristic
const MAX_PAGES = 5;
const DELAY_MS = 5000;
const cutoff = Date.now() - 21*24*60*60*1000;

const titleKw = ['python','backend','back-end','back end','data engineer','data engineering','software engineer','software developer','platform engineer','api developer','developer python','entwickler','softwareentwickler','devops','site reliability','sre','etl','junior developer','junior engineer','flask','django','fastapi','developer','engineer','cloud','infrastructure'];
const tagKw = ['python','backend','data','engineering','devops','api','flask','django','fastapi','docker','aws','postgresql'];
const locKw = ['hamburg','berlin','germany','remote','deutschland','m\u00fcnchen','munich','frankfurt','k\u00f6ln','cologne','deutsch','d\u00fcsseldorf','hannover','stuttgart'];
const engWords = ['the','and','you','we','team','experience','requirements','about','our','will','work','join','role','position'];

function isLikelyEnglish(desc) {
  const sample = (desc||'').substring(0,500).toLowerCase();
  const hits = engWords.filter(w => sample.includes(w)).length;
  return hits >= 3;
}

const allJobs = [];
const seen = new Set();

for (let page = 1; page <= MAX_PAGES; page++) {
  if (page > 1) await new Promise(r => setTimeout(r, DELAY_MS));
  let body;
  try {
    body = await this.helpers.httpRequest({ method: 'GET', url: `https://www.arbeitnow.com/api/job-board-api?page=${page}`, json: true });
  } catch(e) { break; }
  const data = body.data || [];
  if (data.length === 0) break;

  let allOld = true;
  for (const job of data) {
    const created = new Date(job.created_at*1000||job.created_at).getTime();
    if (created > cutoff) allOld = false;

    const t = (job.title||'').toLowerCase();
    const l = (job.location||'').toLowerCase();
    const tags = (job.tags||[]).map(t=>t.toLowerCase());
    const titleMatch = titleKw.some(k=>t.includes(k));
    const tagMatch = tagKw.some(k=>tags.includes(k));
    const locMatch = locKw.some(k=>l.includes(k)) || job.remote;

    if ((titleMatch || tagMatch) && locMatch && created > cutoff) {
      const key = job.slug||job.url||job.title;
      if (!seen.has(key)) {
        seen.add(key);
        allJobs.push(job);
      }
    }
  }
  if (allOld) break;
  const lastPage = body.meta?.last_page || MAX_PAGES;
  if (page >= lastPage) break;
}

if (allJobs.length === 0) return [{ json: { _empty: true } }];

return allJobs.map((j, i) => {
  const desc = (j.description||'').substring(0,5000);
  const jobData = {
    source: 'arbeitnow',
    external_id: j.slug||'',
    url: j.url||`https://www.arbeitnow.com/view/${j.slug}`,
    title: j.title||'',
    company: j.company_name||'',
    location: j.location||'',
    description: desc,
    tags: j.tags||[],
    remote: j.remote||false,
    _likely_english: isLikelyEnglish(desc)
  };
  const filterData = JSON.stringify({
    title: jobData.title,
    company: jobData.company,
    location: jobData.location,
    description: desc.substring(0, 3000),
    tags: jobData.tags,
    url: jobData.url,
    _likely_english: jobData._likely_english
  });
  const b64 = Buffer.from(filterData).toString('base64');
  return { json: { ...jobData, _b64: b64, _idx: i } };
});

// Arbeitsagentur: run multiple server-side filtered searches, fetch details
const BASE = 'https://rest.arbeitsagentur.de/jobboerse/jobsuche-service/pc/v4/jobs';
const DETAIL_BASE = 'https://rest.arbeitsagentur.de/jobboerse/jobsuche-service/pc/v4/jobdetails';
const HEADERS = { 'X-API-Key': 'jobboerse-jobsuche' };
const SEARCH_DELAY = 2000;
const DETAIL_DELAY = 2000;
const MAX_DETAILS = 30;

const searches = [
  'Python Developer',
  'Backend Engineer',
  'Data Engineer',
  'Software Engineer',
  'Python Entwickler',
  'Software Entwickler'
];
const commonParams = 'wo=Hamburg&umkreis=100&veroeffentlichtseit=21&pav=false&zeitarbeit=false&size=50&page=1';

const seenIds = new Set();
const jobs = [];

// Search phase
for (let i = 0; i < searches.length; i++) {
  if (i > 0) await new Promise(r => setTimeout(r, SEARCH_DELAY));
  const url = `${BASE}?was=${encodeURIComponent(searches[i])}&${commonParams}`;
  try {
    const body = await this.helpers.httpRequest({ method: 'GET', url, headers: HEADERS, json: true });
    for (const s of (body.stellenangebote || [])) {
      if (!seenIds.has(s.hashId)) {
        seenIds.add(s.hashId);
        jobs.push(s);
      }
    }
  } catch(e) { /* skip failed search */ }
}

if (jobs.length === 0) return [{ json: { _empty: true } }];

// Detail phase — cap at MAX_DETAILS
const detailJobs = jobs.slice(0, MAX_DETAILS);
for (let i = 0; i < detailJobs.length; i++) {
  if (i > 0) await new Promise(r => setTimeout(r, DETAIL_DELAY));
  try {
    const detail = await this.helpers.httpRequest({ method: 'GET', url: `${DETAIL_BASE}/${detailJobs[i].hashId}`, headers: HEADERS, json: true });
    detailJobs[i]._detail = detail;
  } catch(e) { /* skip */ }
}

// Normalize
return jobs.map((j, i) => {
  const detail = j._detail || {};
  const desc = (detail.stellenbeschreibung || detail.freitextFeld || '').substring(0, 5000);
  const company = typeof j.arbeitgeber === 'object' ? (j.arbeitgeber?.name || '') : (j.arbeitgeber || '');
  const location = j.arbeitsort?.ort || (j.arbeitsorte && j.arbeitsorte[0]?.ort) || '';
  const jobData = {
    source: 'arbeitsagentur',
    external_id: j.hashId || '',
    url: `https://www.arbeitsagentur.de/jobsuche/suche?id=${j.hashId}`,
    title: j.titel || '',
    company: company,
    location: location,
    description: desc,
    tags: [],
    remote: false,
    _likely_english: false
  };
  const filterData = JSON.stringify({
    title: jobData.title,
    company: jobData.company,
    location: jobData.location,
    description: desc.substring(0, 3000),
    tags: jobData.tags,
    url: jobData.url,
    _likely_english: false
  });
  const b64 = Buffer.from(filterData).toString('base64');
  return { json: { ...jobData, _b64: b64, _idx: i } };
});

// Deduplicate merged results by company+title
const all = $input.all().filter(i => !i.json._empty);
const seen = new Set();
const unique = [];

for (const item of all) {
  const job = item.json;
  const key = ((job.company||'') + '|' + (job.title||'')).toLowerCase().trim();
  if (!seen.has(key)) {
    seen.add(key);
    unique.push(job);
  }
}

if (unique.length === 0) return [{ json: { _empty: true } }];
return unique.map((j, i) => ({ json: { ...j, _idx: i } }));

// Filter out already-seen URLs by reading Job URL column from Sheet
const sheetRows = $('Dedup: Read Seen').all();
const seen = new Set(sheetRows.map(r => r.json['Job URL']).filter(Boolean));

const jobs = $('Has Results?').all().filter(item => {
  const url = item.json?.url;
  return url && !seen.has(url);
});

return jobs.length > 0 ? jobs : [{ json: { _empty: true } }];

// Parse filter results — process ALL items, not just the first
const results = [];
for (const item of $input.all()) {
  const stdout = item.json.stdout || '{}';
  let assessment;
  try {
    assessment = JSON.parse(stdout);
  } catch(e) {
    assessment = { fit_score: 0, decision: 'SKIP', cv_variant: 'software', hard_blockers: ['Claude parse error'], reasoning: stdout.substring(0,200) };
  }

  // Get job data from the matching item in Dedup: Filter by index
  const allDedup = $('Dedup: Filter').all();
  const idx = results.length;
  const jobData = (allDedup[idx] || item).json;

  const decision = assessment.decision || 'SKIP';
  results.push({
    json: {
      'Date': new Date().toISOString().slice(0,10),
      'Source': jobData.source || 'arbeitnow',
      'Company': assessment.company || jobData.company || '',
      'Role': assessment.role || jobData.title || '',
      'Location': assessment.location || jobData.location || '',
      'Score': assessment.fit_score || 0,
      'Decision': decision,
      'CV Variant': assessment.cv_variant || 'software',
      'Blockers': (assessment.hard_blockers || []).join('; '),
      'Strong Matches': (assessment.strong_matches || []).join('; '),
      'Reasoning': assessment.reasoning || '',
      'Status': decision === 'SKIP' ? 'skipped' : 'review',
      'Drive Link': '',
      'Job URL': jobData.url || '',
      'Notes': '',
      _assessment: assessment,
      _url: jobData.url || ''
    }
  });
}
return results;
